// ── Extract Submission ID and Chosen Slot from Client's Reply ──
const email = $input.first().json;

// ── 1. Subject extraction ──
let subject = '';
if (email.Subject) {
  subject = String(email.Subject);
} else if (email.subject) {
  subject = String(email.subject);
} else if (Array.isArray(email.payload?.headers)) {
  const hdr = email.payload.headers.find(h => h.name?.toLowerCase() === 'subject');
  if (hdr) subject = hdr.value || '';
} else if (email.headers?.Subject || email.headers?.subject) {
  subject = email.headers.Subject || email.headers.subject;
}

// ── 2. Extract NXF- ID ──
const idMatch = subject.match(/NXF-[\w\d-]+/i);
const submissionId = idMatch ? idMatch[0].toUpperCase() : null;

if (!submissionId) {
  return [{ json: { _skip: true, reason: 'No NXF- ID found in subject', subject } }];
}

// ── 3. Body extraction ──
let body = '';
if (email.text && email.text.trim()) {
  body = email.text;
} else if (email.html && email.html.trim()) {
  body = email.html.replace(/<[^>]+>/g, ' ');
} else if (email.snippet) {
  body = email.snippet;
} else if (email.payload?.body?.data) {
  try { body = Buffer.from(email.payload.body.data, 'base64url').toString('utf-8'); } catch(e) {
    try { body = Buffer.from(email.payload.body.data, 'base64').toString('utf-8'); } catch(e2) {}
  }
} else if (Array.isArray(email.payload?.parts)) {
  const findPart = (parts, mime) => {
    for (const p of parts) {
      if (p.mimeType === mime && p.body?.data) return p.body.data;
      if (Array.isArray(p.parts)) { const n = findPart(p.parts, mime); if (n) return n; }
    }
    return null;
  };
  const raw = findPart(email.payload.parts, 'text/plain') || findPart(email.payload.parts, 'text/html');
  if (raw) {
    try { body = Buffer.from(raw, 'base64url').toString('utf-8').replace(/<[^>]+>/g, ' '); } catch(e) {
      try { body = Buffer.from(raw, 'base64').toString('utf-8').replace(/<[^>]+>/g, ' '); } catch(e2) {}
    }
  }
}

// ── 4. Extract slot choice ──
const wordToNum = { one:1, two:2, three:3, four:4, five:5 };
const patterns = [
  /(?:option|slot|choice|#)\s*([1-5])/i,
  /\b([1-5])\b/,
  /\b(one|two|three|four|five)\b/i,
];
let slotChoice = null;
for (const pat of patterns) {
  const m = body.match(pat);
  if (m) { slotChoice = parseInt(m[1]) || wordToNum[m[1]?.toLowerCase()] || null; if (slotChoice) break; }
}
if (!slotChoice && /\b(yes|ok|okay|confirm|confirmed|works|good|perfect|sure|great|sounds good|see you|deal|fine)\b/i.test(body)) {
  slotChoice = 1;
}
if (!slotChoice) slotChoice = 1;

// ── 5. Client email extraction ──
let clientEmail = '';
const rawFrom = email.From || email.from || '';
if (typeof rawFrom === 'string') {
  clientEmail = rawFrom;
} else if (rawFrom?.value?.[0]?.address) {
  clientEmail = rawFrom.value[0].address;
} else if (Array.isArray(rawFrom)) {
  clientEmail = rawFrom[0]?.address || rawFrom[0] || '';
}
if (!clientEmail && Array.isArray(email.payload?.headers)) {
  const hdr = email.payload.headers.find(h => h.name?.toLowerCase() === 'from');
  if (hdr) clientEmail = hdr.value || '';
}
const emailMatch = clientEmail.match(/<(.+?)>/);
if (emailMatch) clientEmail = emailMatch[1].trim();

return [{
  json: {
    _skip: false,
    submissionId,
    slotChoice,
    clientEmail,
    emailSubject: subject,
    emailBody: body.slice(0, 600)
  }
}];

// ── Merge Reply Data with Original Submission + Pick Chosen Slot ──
const replyData = $('Extract ID + Slot Choice').first().json;
const sheetRow  = $input.first().json;

// Guard: if no sheet row found for this submission ID, stop cleanly
const hasRow = sheetRow && (
  sheetRow['Submission ID'] || sheetRow.submissionId ||
  sheetRow['Email']         || sheetRow.email ||
  sheetRow['First Name']    || sheetRow.firstName
);
if (!hasRow) {
  throw new Error(
    'No sheet row found for ' + replyData.submissionId +
    '. The original form submission may have been saved before the sheet was configured.'
  );
}

// Parse slots JSON saved by Workflow 1
let slots = [];
try {
  const raw = sheetRow['Slots JSON'] || sheetRow.slotsJSON || '[]';
  slots = JSON.parse(raw);
} catch(e) { slots = []; }

if (!slots.length) {
  throw new Error(
    'Slots JSON is empty for ' + replyData.submissionId +
    '. The Slots JSON column may be missing from the sheet header row.'
  );
}

// Get chosen slot (1-indexed)
const choice = parseInt(replyData.slotChoice) || 1;
const chosen = slots.find(s => s.index === choice) || slots[choice - 1] || slots[0];

// Client email: prefer reply address, fall back to sheet
const clientEmail = replyData.clientEmail || sheetRow['Email'] || sheetRow.email || '';

// Country and timezone from sheet (populated by Workflow 1)
const country  = sheetRow['Country']         || sheetRow.country  || '';
const clientTz = sheetRow['Client Timezone'] || sheetRow.clientTz || '';

// labelClient shows time in client's own timezone (set by Workflow 1);
// falls back to IST label if country was unknown at submission time.
const chosenSlotLabelClient = chosen.labelClient || chosen.label;

return [{
  json: {
    firstName:              sheetRow['First Name']  || sheetRow.firstName  || 'Client',
    lastName:               sheetRow['Last Name']   || sheetRow.lastName   || '',
    email:                  clientEmail,
    phone:                  sheetRow['Phone']        || sheetRow.phone      || '',
    country,
    clientTz,
    company:                sheetRow['Company']      || sheetRow.company    || '',
    service:                sheetRow['Service']      || sheetRow.service    || 'Strategy Call',
    message:                sheetRow['Message']      || sheetRow.message    || '',
    submissionId:           replyData.submissionId,
    chosenSlotLabel:        chosen.label,
    chosenSlotLabelClient,
    chosenSlotStartISO:     chosen.startISO,
    chosenSlotEndISO:       chosen.endISO,
    rowIndex:               sheetRow._rowNumber || sheetRow.row || 2
  }
}];

