// ── Merge booking data with the calendar event result ──
const booking  = $('Prepare Booking Data').first().json;
const calEvent = $input.first().json;

const meetLink = calEvent.hangoutLink || calEvent.conferenceData?.entryPoints?.[0]?.uri || 'https://meet.google.com';
const calLink  = calEvent.htmlLink || '';
const eventId  = calEvent.id || '';

return [{
  json: {
    ...booking,
    meetLink,
    calLink,
    eventId,
    bookingConfirmedAt: new Date().toISOString()
  }
}];

